llm_verdict.message:
{
  "plan_description": "Ensure NetworkManager DNS mode is properly configured to dnsmasq. Create or update /etc/NetworkManager/conf.d/dns.conf with a [main] section containing dns=dnsmasq, then restart NetworkManager service to apply the change.",
  "commands": [
    {
      "command": "read_file /etc/NetworkManager/conf.d/dns.conf"
    },
    {
      "command": "write_file /etc/NetworkManager/conf.d/dns.conf <<EOF\n[main]\ndns=dnsmasq\nEOF"
    },
    {
      "command": "run_cmd systemctl restart NetworkManager"
    }
  ]
}

